const data = $input.first().json;
const size = data.size;
const values = data.value || {};
const dimensions = data.dimension;

const currencyKeys = Object.keys(dimensions.currency.category.index);
const timeKeys = Object.keys(dimensions.time.category.index);

const results = [];
const ratesByDate = {};

for (const currency of currencyKeys) {
  const i_currency = dimensions.currency.category.index[currency];
  for (const time of timeKeys) {
    const i_time = dimensions.time.category.index[time];
    const idx = i_currency * size[4] + i_time;
    const val = values[idx.toString()];

    if (val !== undefined && val !== null) {
      if (!ratesByDate[time]) {
        ratesByDate[time] = {};
      }
      ratesByDate[time][currency] = val;
    }
  }
}

for (const date of Object.keys(ratesByDate)) {
  const rates = ratesByDate[date];
  if (rates.USD) {
    results.push({
      base_currency: 'USD',
      target_currency: 'EUR',
      rate: 1 / rates.USD,
      rate_date: date
    });
  }
  if (rates.HKD) {
    results.push({
      base_currency: 'EUR',
      target_currency: 'HKD',
      rate: rates.HKD,
      rate_date: date
    });
  }
}

return results;
